##=============================================================================
## TARGETR API MOCK (WireMock)
##=============================================================================
## Temporary mock of the TargetR API to unblock Lexxi MVP1 development.
## Serves all required endpoints defined in the TargetR API Requirements doc.
##
## Test data available:
##   pt-001 / rpt-001 → Patient-Alpha, female 1975, BRCA panel, completed
##   pt-002 / rpt-002 → Patient-Beta,  male   1982, Heart panel, completed
##   pt-003 / rpt-003 → Patient-Gamma, female 1968, Comprehensive panel, processing
##
## Any Bearer token is accepted (mock does not validate auth).
## Image must be built and pushed to ACR before first apply:
##   cd mocks/targetr-api && ./build-push.sh <acr-login-server>
##

resource "azurerm_container_app" "targetr_mock" {

  name                         = "${local.resource_prefix}-targetr-mock"
  container_app_environment_id = azurerm_container_app_environment.env.id
  resource_group_name          = azurerm_resource_group.rg.name
  revision_mode                = "Single"

  ingress {
    allow_insecure_connections = false
    external_enabled           = true
    target_port                = 8080
    transport                  = "http"

    traffic_weight {
      latest_revision = true
      percentage      = 100
    }
  }

  template {
    container {
      name   = "wiremock"
      image  = "${var.shared_container_registry_login_server}/targetr-api-mock:latest"
      cpu    = 0.25
      memory = "0.5Gi"
    }

    min_replicas = 1
    max_replicas = 1
  }

  registry {
    server               = var.shared_container_registry_login_server
    username             = var.shared_container_registry_username
    password_secret_name = "acr-password"
  }

  secret {
    name  = "acr-password"
    value = var.shared_container_registry_password
  }

  tags = local.tags

  lifecycle {
    ignore_changes = [workload_profile_name]
  }

  depends_on = [azurerm_container_app_environment.env]
}

